import React from "react";
import {
  Container,
  Sleeve,
  VinylRecord,
  Circle,
  BackgroundImage,
  Overlay,
  StyledHeading,
  StyledText,
} from "./styles";
import templeSmoke from "../../Assets/temple_smoke.png";
import templeSmokeLive from "../../Assets/temple_smoke_live.jpeg";
import { useTheme } from "../../Theme";

const RecordCover: React.FC = () => {
  const { theme } = useTheme();

  return (
    <Container>
      <BackgroundImage src={templeSmokeLive} />
      <Overlay />
      <VinylRecord>
        <Circle diameter={34} />
        <Circle diameter={32} />
        <Circle diameter={30} />
        <Circle diameter={28} />
        <Circle diameter={26} />
        <Circle diameter={24} />
        <Circle diameter={22} />
        <Circle diameter={20} />
        <Circle diameter={18} />
        <Circle diameter={16} />
        <Circle diameter={14} color={"white"} />
        <Circle diameter={3} color={"black"} />
      </VinylRecord>
      <Sleeve src={templeSmoke} />
      <StyledHeading theme={theme}>Temple Smoke</StyledHeading>
      <StyledText theme={theme}>A really good band</StyledText>
    </Container>
  );
};

export default RecordCover;
